import{_ as e,o as a,c as o,ag as l}from"./chunks/framework.DEs8X8sU.js";const g=JSON.parse('{"title":"Google レビュー連携と満足度評価","description":"","frontmatter":{"feature_id":"L-7","title":"Google レビュー連携と満足度評価","chapter":20,"plan":["all"],"role":["owner","manager"],"audience":"店長以上","keywords":["Google","レビュー","Place ID","満足度","星評価","リピート率"],"related":["16-settings","17-customer","13-reports"],"last_updated":"2026-04-19T00:00:00.000Z","maintainer":"POSLA運営"},"headers":[],"relativePath":"tenant/20-google-review.md","filePath":"tenant/20-google-review.md"}'),s={name:"tenant/20-google-review.md"};function d(i,t,r,n,c,h){return a(),o("div",null,[...t[0]||(t[0]=[l(`<h1 id="_20-googleレビュー連携と満足度評価" tabindex="-1">20. Googleレビュー連携と満足度評価 <a class="header-anchor" href="#_20-googleレビュー連携と満足度評価" aria-label="Permalink to &quot;20. Googleレビュー連携と満足度評価&quot;">​</a></h1><p>POSLA には、お客様の満足度を収集し、高評価のお客様を Google レビューに自動誘導する仕組みがあります。低評価は内部で店舗にだけ通知され、Google には流れない設計です。</p><div class="tip custom-block"><p class="custom-block-title">この章の対象</p><ul><li><strong>オーナー / 店長</strong>: Google Place ID の取得・設定（20.4 参照）</li><li><strong>店舗運営チーム全員</strong>: 満足度評価データの活用（20.5 参照）</li></ul><p>実装関連:</p><ul><li>客側 UI: <code>public/customer/menu.html</code> L2104</li><li>API: <code>api/customer/satisfaction-rating.php</code>（POST、認証なし、セッショントークン検証あり）</li><li>DB: <code>satisfaction_ratings</code> テーブル</li></ul></div><hr><h2 id="_20-1-満足度評価の仕組み" tabindex="-1">20.1 満足度評価の仕組み <a class="header-anchor" href="#_20-1-満足度評価の仕組み" aria-label="Permalink to &quot;20.1 満足度評価の仕組み&quot;">​</a></h2><h3 id="_20-1-1-評価のタイミング" tabindex="-1">20.1.1 評価のタイミング <a class="header-anchor" href="#_20-1-1-評価のタイミング" aria-label="Permalink to &quot;20.1.1 評価のタイミング&quot;">​</a></h3><p>お客様のセルフオーダー画面で、注文した品目が <strong>すべて <code>served</code>（提供済）</strong> ステータスになると、満足度評価のプロンプトが画面下部に表示されます。</p><p>評価表示の条件（実装: <code>menu.html</code>）:</p><ul><li>注文の品目すべてが <code>served</code> ステータス</li><li>セッションが有効（4 時間以内）</li><li>同じ注文に対して未評価</li><li>店舗で満足度評価機能が ON（デフォルト ON）</li></ul><h3 id="_20-1-2-評価の方法" tabindex="-1">20.1.2 評価の方法 <a class="header-anchor" href="#_20-1-2-評価の方法" aria-label="Permalink to &quot;20.1.2 評価の方法&quot;">​</a></h3><p>星（1〜5）ベースの評価インターフェースが表示され、お客様は直感的に満足度を入力できます。</p><table tabindex="0"><thead><tr><th>星</th><th>意味</th></tr></thead><tbody><tr><td>⭐ 1</td><td>とても不満</td></tr><tr><td>⭐⭐ 2</td><td>不満</td></tr><tr><td>⭐⭐⭐ 3</td><td>普通</td></tr><tr><td>⭐⭐⭐⭐ 4</td><td>満足</td></tr><tr><td>⭐⭐⭐⭐⭐ 5</td><td>とても満足</td></tr></tbody></table><p>評価後、コメント欄が表示され、自由記述も可能です（任意）。</p><h3 id="_20-1-3-評価データの活用先" tabindex="-1">20.1.3 評価データの活用先 <a class="header-anchor" href="#_20-1-3-評価データの活用先" aria-label="Permalink to &quot;20.1.3 評価データの活用先&quot;">​</a></h3><table tabindex="0"><thead><tr><th>活用先</th><th>説明</th></tr></thead><tbody><tr><td><strong>スタッフ評価レポート</strong></td><td>該当注文を取ったスタッフ（<code>orders.staff_id</code>）の平均評価に集計（13 章 13.5）</td></tr><tr><td><strong>メニュー別レポート</strong></td><td>品目ごとの平均評価で人気・不評メニューを把握</td></tr><tr><td><strong>KDS 低評価アラート</strong></td><td>1〜2 星評価が出ると KDS 画面に <strong>赤バナー</strong>で表示（17.W 参照）</td></tr><tr><td><strong>Google レビュー誘導</strong></td><td>4〜5 星のお客様に Google マップへの投稿リンクを表示（20.2）</td></tr></tbody></table><hr><h2 id="_20-2-googleレビューへの誘導" tabindex="-1">20.2 Googleレビューへの誘導 <a class="header-anchor" href="#_20-2-googleレビューへの誘導" aria-label="Permalink to &quot;20.2 Googleレビューへの誘導&quot;">​</a></h2><h3 id="_20-2-1-誘導の仕組み" tabindex="-1">20.2.1 誘導の仕組み <a class="header-anchor" href="#_20-2-1-誘導の仕組み" aria-label="Permalink to &quot;20.2.1 誘導の仕組み&quot;">​</a></h3><p>実装: <code>public/customer/menu.html</code> L2104</p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (rating </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> settings.googlePlaceId) {</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // Google レビュー投稿リンクを表示</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  var</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> reviewUrl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://search.google.com/local/writereview?placeid=&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> </span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">                  +</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> encodeURIComponent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(settings.googlePlaceId);</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // ...</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><ul><li><strong>4〜5 星（高評価）</strong> をつけたお客様にのみ、Google レビュー投稿リンクが表示される</li><li><strong>1〜3 星（中・低評価）</strong> にはリンクは表示されない（マイナスレビューの拡散防止）</li><li>リンクをタップすると、Google マップのレビュー投稿画面が新タブで開く</li></ul><h3 id="_20-2-2-表示メッセージ" tabindex="-1">20.2.2 表示メッセージ <a class="header-anchor" href="#_20-2-2-表示メッセージ" aria-label="Permalink to &quot;20.2.2 表示メッセージ&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ありがとうございます！</span></span>
<span class="line"><span>お客様の声は私たちの励みになります。</span></span>
<span class="line"><span>よろしければ Google マップでもレビューを書いていただけませんか？</span></span>
<span class="line"><span>[ ⭐ Google でレビューを書く ]</span></span></code></pre></div><h3 id="_20-2-3-リンク-url-の形式" tabindex="-1">20.2.3 リンク URL の形式 <a class="header-anchor" href="#_20-2-3-リンク-url-の形式" aria-label="Permalink to &quot;20.2.3 リンク URL の形式&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://search.google.com/local/writereview?placeid=ChIJrTLr-GyuEmsRBfy61i59si0</span></span></code></pre></div><p><code>placeid=</code> の後に <strong>Google Place ID</strong> を URL エンコードして付与されます。</p><hr><h2 id="_20-3-効果と-kpi" tabindex="-1">20.3 効果と KPI <a class="header-anchor" href="#_20-3-効果と-kpi" aria-label="Permalink to &quot;20.3 効果と KPI&quot;">​</a></h2><h3 id="_20-3-1-期待効果" tabindex="-1">20.3.1 期待効果 <a class="header-anchor" href="#_20-3-1-期待効果" aria-label="Permalink to &quot;20.3.1 期待効果&quot;">​</a></h3><ul><li><strong>Google レビュー投稿数の増加</strong>: 平均 2〜3 倍（POSLA 既存導入店舗の事例）</li><li><strong>平均評価の向上</strong>: 4 つ星以上だけ誘導するため、Google マップ上の星平均が上がる傾向</li><li><strong>新規来店促進</strong>: Google マップでお店を見つけたお客様が「行ってみよう」となる確率向上</li></ul><h3 id="_20-3-2-計測すべき指標" tabindex="-1">20.3.2 計測すべき指標 <a class="header-anchor" href="#_20-3-2-計測すべき指標" aria-label="Permalink to &quot;20.3.2 計測すべき指標&quot;">​</a></h3><ul><li>月次の Google マップ閲覧数</li><li>レビュー投稿数（前年比・前月比）</li><li>新規来店者数（Google マップ経由）</li></ul><hr><h2 id="_20-4-google-place-id-の取得・設定" tabindex="-1">20.4 Google Place ID の取得・設定 <a class="header-anchor" href="#_20-4-google-place-id-の取得・設定" aria-label="Permalink to &quot;20.4 Google Place ID の取得・設定&quot;">​</a></h2><h3 id="_20-4-1-place-id-とは" tabindex="-1">20.4.1 Place ID とは <a class="header-anchor" href="#_20-4-1-place-id-とは" aria-label="Permalink to &quot;20.4.1 Place ID とは&quot;">​</a></h3><p>Google マップ上の <strong>店舗を一意に識別する ID</strong> です。例: <code>ChIJrTLr-GyuEmsRBfy61i59si0</code></p><h3 id="_20-4-2-place-id-の取得方法" tabindex="-1">20.4.2 Place ID の取得方法 <a class="header-anchor" href="#_20-4-2-place-id-の取得方法" aria-label="Permalink to &quot;20.4.2 Place ID の取得方法&quot;">​</a></h3><h4 id="方法-a-google-の公式ツール-推奨" tabindex="-1">方法 A: Google の公式ツール（推奨） <a class="header-anchor" href="#方法-a-google-の公式ツール-推奨" aria-label="Permalink to &quot;方法 A: Google の公式ツール（推奨）&quot;">​</a></h4><ol><li>ブラウザで <a href="https://developers.google.com/maps/documentation/places/web-service/place-id" target="_blank" rel="noreferrer">Place ID Finder</a> を開く</li><li>検索ボックスに <strong>店舗名</strong> または <strong>住所</strong> を入力（例: 「松乃家 渋谷店」）</li><li>候補から自店舗を選択</li><li>地図の下に表示される <strong>Place ID 文字列</strong>（<code>ChIJ...</code> で始まる）をコピー</li></ol><h4 id="方法-b-google-マップから取得" tabindex="-1">方法 B: Google マップから取得 <a class="header-anchor" href="#方法-b-google-マップから取得" aria-label="Permalink to &quot;方法 B: Google マップから取得&quot;">​</a></h4><ol><li><a href="https://www.google.com/maps" target="_blank" rel="noreferrer">Google Maps</a> で自店舗を検索</li><li>店舗のページを開く</li><li>URL の中に <code>!1s</code> の後ろに表示される ID を確認</li><li>ただし、この ID は内部 ID であり Place ID とは違うフォーマット — 方法 A 推奨</li></ol><h3 id="_20-4-3-posla-への設定方法" tabindex="-1">20.4.3 POSLA への設定方法 <a class="header-anchor" href="#_20-4-3-posla-への設定方法" aria-label="Permalink to &quot;20.4.3 POSLA への設定方法&quot;">​</a></h3><ol><li>owner / manager で <code>dashboard.html</code> にログイン</li><li>上部タブ <strong>【店舗設定】</strong> → サブタブ <strong>【店舗設定】</strong></li><li>画面を下にスクロール → <strong>「Google レビュー設定」</strong> セクション</li><li><strong>「Google Place ID」</strong> 入力欄に取得した ID を貼り付け</li><li><strong>【設定を保存】</strong> ボタン</li><li>お客様のセルフオーダー画面に即反映（3 分のメニューキャッシュ後）</li></ol><h3 id="_20-4-4-設定後の確認" tabindex="-1">20.4.4 設定後の確認 <a class="header-anchor" href="#_20-4-4-設定後の確認" aria-label="Permalink to &quot;20.4.4 設定後の確認&quot;">​</a></h3><ol><li>お客様役で QR を読んでセルフオーダー画面を開く</li><li>テスト注文を入れて全品目を <code>served</code> まで進める</li><li>満足度評価ダイアログで <strong>5 星</strong> を選ぶ</li><li><strong>Google レビュー投稿リンク</strong>が表示されればOK</li><li>リンクをタップして Google マップのレビュー画面が開けばOK</li></ol><hr><h2 id="_20-5-評価データの活用ストーリー" tabindex="-1">20.5 評価データの活用ストーリー <a class="header-anchor" href="#_20-5-評価データの活用ストーリー" aria-label="Permalink to &quot;20.5 評価データの活用ストーリー&quot;">​</a></h2><h3 id="_20-5-1-月次定例ミーティング" tabindex="-1">20.5.1 月次定例ミーティング <a class="header-anchor" href="#_20-5-1-月次定例ミーティング" aria-label="Permalink to &quot;20.5.1 月次定例ミーティング&quot;">​</a></h3><p>毎月の店長会議で:</p><ol><li>13 章 13.5 スタッフ評価レポートを開く</li><li>過去 30 日の評価平均を確認</li><li><strong>下位 3 名のスタッフ</strong> に対する研修プラン</li><li><strong>上位 3 名</strong> にボーナス・表彰</li><li>メニュー別評価で <strong>下位 3 品</strong> の改善・廃止検討</li></ol><h3 id="_20-5-2-kds-低評価リアルタイム対応" tabindex="-1">20.5.2 KDS 低評価リアルタイム対応 <a class="header-anchor" href="#_20-5-2-kds-低評価リアルタイム対応" aria-label="Permalink to &quot;20.5.2 KDS 低評価リアルタイム対応&quot;">​</a></h3><ol><li>営業中、KDS 画面に <strong>赤バナーで低評価アラート</strong>が表示される</li><li>その場でキッチンで品質確認（同じ問題が続いていないか）</li><li>お客様がまだ店内にいれば、ホールスタッフが伺ってお詫び</li><li>必要なら割引・サービス品で対応</li><li>翌朝のミーティングで原因を深掘り</li></ol><h3 id="_20-5-3-google-レビュー継続的-kpi" tabindex="-1">20.5.3 Google レビュー継続的 KPI <a class="header-anchor" href="#_20-5-3-google-レビュー継続的-kpi" aria-label="Permalink to &quot;20.5.3 Google レビュー継続的 KPI&quot;">​</a></h3><ul><li><strong>目標</strong>: 月 5 件以上の新規 Google レビュー</li><li><strong>目標</strong>: 平均星評価 <strong>4.5 以上</strong> を維持</li><li><strong>対策</strong>: 評価が落ちたら原因究明（メニュー・スタッフ・接客フロー）</li></ul><hr><h2 id="_20-6-関連設定との連携" tabindex="-1">20.6 関連設定との連携 <a class="header-anchor" href="#_20-6-関連設定との連携" aria-label="Permalink to &quot;20.6 関連設定との連携&quot;">​</a></h2><h3 id="_20-6-1-16-章「店舗設定」との関係" tabindex="-1">20.6.1 16 章「店舗設定」との関係 <a class="header-anchor" href="#_20-6-1-16-章「店舗設定」との関係" aria-label="Permalink to &quot;20.6.1 16 章「店舗設定」との関係&quot;">​</a></h3><p>Google Place ID は <strong>16-settings.md</strong> の 16.X セクションで設定します。本章はその活用方法を解説。</p><h3 id="_20-6-2-13-章「レポート」との関係" tabindex="-1">20.6.2 13 章「レポート」との関係 <a class="header-anchor" href="#_20-6-2-13-章「レポート」との関係" aria-label="Permalink to &quot;20.6.2 13 章「レポート」との関係&quot;">​</a></h3><p>満足度評価データは <strong>13-reports.md</strong> の 13.5 スタッフ評価レポートに自動集計されます。</p><h3 id="_20-6-3-17-章「セルフオーダー画面」との関係" tabindex="-1">20.6.3 17 章「セルフオーダー画面」との関係 <a class="header-anchor" href="#_20-6-3-17-章「セルフオーダー画面」との関係" aria-label="Permalink to &quot;20.6.3 17 章「セルフオーダー画面」との関係&quot;">​</a></h3><p>お客様視点の挙動詳細は <strong>17-customer.md</strong> の 17.W 満足度評価セクション参照。</p><h3 id="_20-6-4-7-章「kds」との関係" tabindex="-1">20.6.4 7 章「KDS」との関係 <a class="header-anchor" href="#_20-6-4-7-章「kds」との関係" aria-label="Permalink to &quot;20.6.4 7 章「KDS」との関係&quot;">​</a></h3><p>低評価アラートの KDS 画面表示は <strong>07-kds.md</strong> の 7.7.X 低評価アラート参照。</p><hr><h2 id="_20-x-よくある質問" tabindex="-1">20.X よくある質問 <a class="header-anchor" href="#_20-x-よくある質問" aria-label="Permalink to &quot;20.X よくある質問&quot;">​</a></h2><p><strong>Q1.</strong> Place ID の取得方法</p><p><strong>A1.</strong> <a href="https://developers.google.com/maps/documentation/places/web-service/place-id" target="_blank" rel="noreferrer">Google Place ID Finder</a> で店舗名検索が最も簡単・確実。</p><p><strong>Q2.</strong> 低評価のお客様も Google に誘導される？</p><p><strong>A2.</strong> <strong>誘導されません</strong>（4〜5 星のみ）。1〜3 星は店舗に内部通知のみ。Google マップ上の評価が下がるリスクを減らします。</p><p><strong>Q3.</strong> 設定したのにレビューリンクが出ない</p><p><strong>A3.</strong> 以下を確認:</p><ul><li>セルフメニューを再読み込み（3 分のメニューキャッシュ）</li><li>Place ID が正しい形式（<code>ChIJ...</code> で始まる）</li><li>評価が 4 以上か（3 以下なら表示しない仕様）</li></ul><p><strong>Q4.</strong> Place ID 設定なしでも満足度評価は使える？</p><p><strong>A4.</strong> はい。満足度評価データは内部レポート用にも使えます。Google レビュー誘導だけが無効になる。</p><p><strong>Q5.</strong> 評価データはどこに保存される？</p><p><strong>A5.</strong> <code>satisfaction_ratings</code> テーブル。<code>orders.id</code> と紐付けて保存。</p><p><strong>Q6.</strong> 評価 UI のデザインを変えたい</p><p><strong>A6.</strong> 現状はカスタマイズ不可（POSLA 標準デザイン）。将来的にロゴ色・テーマカラーが反映される予定。</p><p><strong>Q7.</strong> お客様が複数回評価できる？</p><p><strong>A7.</strong> 同じ注文に対しては 1 回のみ。同じテーブルセッションで別の注文があれば、それぞれ評価可。</p><p><strong>Q8.</strong> 英語のお客様にも対応している？</p><p><strong>A8.</strong> はい。多言語対応（5 言語）で評価 UI が翻訳されます。Google レビュー画面は Google 側で多言語対応。</p><p><strong>Q9.</strong> Stripe Reader S700 とは関係ある？</p><p><strong>A9.</strong> ありません。S700 はカード決済用、満足度評価は注文後の完全に別フロー。</p><p><strong>Q10.</strong> Google レビュー数が増えない</p><p><strong>A10.</strong> 以下を確認:</p><ul><li>平均評価が 4 未満（リンク表示されない）</li><li>お客様がリンクをタップしていない（リンクが目立たない可能性）</li><li>Google アカウントを持っていない（投稿不可）</li><li>営業件数自体が少ない（来店数増加の施策も必要）</li></ul><hr><h2 id="_20-y-トラブルシューティング" tabindex="-1">20.Y トラブルシューティング <a class="header-anchor" href="#_20-y-トラブルシューティング" aria-label="Permalink to &quot;20.Y トラブルシューティング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>評価ダイアログが出ない</td><td>全品目が served になっていない</td><td>KDS で全品 served にする</td></tr><tr><td>評価ダイアログが出ない</td><td>既に評価済み</td><td>同じ注文には 1 回のみ</td></tr><tr><td>Google リンクが出ない</td><td>評価 3 以下 / Place ID 未設定</td><td>4-5 星かつ Place ID 設定要</td></tr><tr><td>Google リンクが古い店舗を開く</td><td>Place ID 入力ミス</td><td>Place ID 再取得・再設定</td></tr><tr><td>評価データがレポートに反映されない</td><td>キャッシュ</td><td>翌日まで待つ（一部レポートは日次集計）</td></tr></tbody></table><hr><h2 id="_20-z-技術補足" tabindex="-1">20.Z 技術補足 <a class="header-anchor" href="#_20-z-技術補足" aria-label="Permalink to &quot;20.Z 技術補足&quot;">​</a></h2><h3 id="db" tabindex="-1">DB <a class="header-anchor" href="#db" aria-label="Permalink to &quot;DB&quot;">​</a></h3><ul><li><code>satisfaction_ratings</code> テーブル <ul><li><code>id</code>, <code>tenant_id</code>, <code>store_id</code>, <code>table_id</code>, <code>order_id</code>, <code>order_item_id</code>（任意）, <code>menu_item_id</code>, <code>item_name</code>, <code>rating</code> (1-5), <code>comment</code>, <code>created_at</code></li></ul></li><li><code>store_settings.google_place_id</code> カラム</li><li><code>store_settings.satisfaction_rating_enabled</code> カラム（デフォルト 1）</li></ul><h3 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h3><ul><li><code>POST /api/customer/satisfaction-rating.php</code> — 評価送信（認証なし、セッショントークン検証あり） <ul><li>パラメータ: <code>store_id</code>, <code>table_id</code>, <code>session_token</code>, <code>order_id</code>, <code>order_item_id</code>, <code>menu_item_id</code>, <code>item_name</code>, <code>rating</code></li><li>エラー: <code>MISSING_FIELDS</code> (400), <code>INVALID_RATING</code> (400, 1-5 範囲外), <code>INVALID_SESSION</code> (401)</li></ul></li></ul><h3 id="フロント" tabindex="-1">フロント <a class="header-anchor" href="#フロント" aria-label="Permalink to &quot;フロント&quot;">​</a></h3><ul><li><code>public/customer/menu.html</code> L2104 (高評価判定 + Google リンク表示)</li><li>評価 UI レンダリング: 同じ menu.html 内のインラインスクリプト</li></ul><h3 id="連携先-url" tabindex="-1">連携先 URL <a class="header-anchor" href="#連携先-url" aria-label="Permalink to &quot;連携先 URL&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://search.google.com/local/writereview?placeid={URLエンコードされた placeId}</span></span></code></pre></div><hr><h2 id="関連章" tabindex="-1">関連章 <a class="header-anchor" href="#関連章" aria-label="Permalink to &quot;関連章&quot;">​</a></h2><ul><li><a href="./13-reports.html">13. レポート</a> — スタッフ評価レポート集計</li><li><a href="./16-settings.html">16. 店舗設定</a> — Google Place ID の設定手順</li><li><a href="./17-customer.html">17. セルフオーダー</a> — 17.W 満足度評価詳細</li><li><a href="./07-kds.html">7. KDS</a> — 7.7.X 低評価アラート</li></ul><h2 id="_20-7-操作前チェックリスト-google-place-id-設定前" tabindex="-1">20.7 操作前チェックリスト（Google Place ID 設定前） <a class="header-anchor" href="#_20-7-操作前チェックリスト-google-place-id-設定前" aria-label="Permalink to &quot;20.7 操作前チェックリスト（Google Place ID 設定前）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>確認項目</th><th>確認方法</th><th>NG時の対応</th></tr></thead><tbody><tr><td>1</td><td>Google マップ上に <strong>店舗が登録済み</strong></td><td><a href="https://maps.google.com" target="_blank" rel="noreferrer">https://maps.google.com</a> で店舗名検索</td><td>Google ビジネスプロフィール (<a href="https://business.google.com" target="_blank" rel="noreferrer">https://business.google.com</a>) で新規登録</td></tr><tr><td>2</td><td>ビジネスプロフィールが <strong>オーナー確認済み</strong></td><td>「あなたが管理しています」表示</td><td>はがき / 電話で確認 (Google 案内に従う)</td></tr><tr><td>3</td><td>店舗名・住所が <strong>正確</strong> に登録</td><td>Google マップで詳細確認</td><td>ビジネスプロフィールで修正</td></tr><tr><td>4</td><td>自分のロールが <strong>owner / manager</strong></td><td>dashboard.html ヘッダー右上</td><td>owner / manager に依頼</td></tr><tr><td>5</td><td>POSLA に <strong>店舗 GPS 座標</strong> が設定済み</td><td>16 章 16.X 参照</td><td>店舗設定タブで緯度経度を入力</td></tr><tr><td>6</td><td>満足度評価機能が <strong>ON</strong> (デフォルト ON)</td><td>店舗設定 → satisfaction_rating_enabled</td><td>ON に切り替え</td></tr></tbody></table><h2 id="_20-8-入力フィールド詳細表" tabindex="-1">20.8 入力フィールド詳細表 <a class="header-anchor" href="#_20-8-入力フィールド詳細表" aria-label="Permalink to &quot;20.8 入力フィールド詳細表&quot;">​</a></h2><h3 id="_20-8-1-google-レビュー設定-店舗設定タブ" tabindex="-1">20.8.1 Google レビュー設定（店舗設定タブ） <a class="header-anchor" href="#_20-8-1-google-レビュー設定-店舗設定タブ" aria-label="Permalink to &quot;20.8.1 Google レビュー設定（店舗設定タブ）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>フィールド</th><th>DB カラム</th><th style="text-align:center;">必須</th><th>形式</th><th>例</th></tr></thead><tbody><tr><td>Google Place ID</td><td><code>store_settings.google_place_id</code></td><td style="text-align:center;">任意</td><td><code>ChIJ</code> で始まる文字列</td><td><code>ChIJrTLr-GyuEmsRBfy61i59si0</code></td></tr><tr><td>満足度評価機能</td><td><code>store_settings.satisfaction_rating_enabled</code></td><td style="text-align:center;">必須</td><td><code>0</code> / <code>1</code></td><td><code>1</code> (ON)</td></tr></tbody></table><h3 id="_20-8-2-満足度評価-api-リクエスト-お客様側" tabindex="-1">20.8.2 満足度評価 API リクエスト（お客様側） <a class="header-anchor" href="#_20-8-2-満足度評価-api-リクエスト-お客様側" aria-label="Permalink to &quot;20.8.2 満足度評価 API リクエスト（お客様側）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>フィールド</th><th style="text-align:center;">必須</th><th>形式</th><th>例</th></tr></thead><tbody><tr><td><code>store_id</code></td><td style="text-align:center;">✅</td><td>INT</td><td><code>2</code></td></tr><tr><td><code>table_id</code></td><td style="text-align:center;">✅</td><td>INT</td><td><code>5</code></td></tr><tr><td><code>session_token</code></td><td style="text-align:center;">✅</td><td>64 文字 hex</td><td><code>a1b2c3...</code></td></tr><tr><td><code>order_id</code></td><td style="text-align:center;">✅</td><td>INT</td><td><code>12345</code></td></tr><tr><td><code>order_item_id</code></td><td style="text-align:center;">任意</td><td>INT</td><td><code>67890</code></td></tr><tr><td><code>menu_item_id</code></td><td style="text-align:center;">任意</td><td>INT</td><td><code>100</code></td></tr><tr><td><code>item_name</code></td><td style="text-align:center;">任意</td><td>文字列 (最大 200)</td><td><code>カルボナーラ</code></td></tr><tr><td><code>rating</code></td><td style="text-align:center;">✅</td><td>INT (1-5)</td><td><code>5</code></td></tr><tr><td><code>comment</code></td><td style="text-align:center;">任意</td><td>文字列 (最大 1000)</td><td><code>美味しかった</code></td></tr></tbody></table><p>エラーコード:</p><ul><li><code>MISSING_FIELDS</code> (400): 必須項目欠落</li><li><code>INVALID_RATING</code> (400): 1-5 範囲外</li><li><code>INVALID_SESSION</code> (401): セッショントークン不正</li></ul><h2 id="_20-9-画面遷移の-ascii-描写" tabindex="-1">20.9 画面遷移の ASCII 描写 <a class="header-anchor" href="#_20-9-画面遷移の-ascii-描写" aria-label="Permalink to &quot;20.9 画面遷移の ASCII 描写&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[お客様セルフオーダー (menu.html)]</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        │ 注文 → 全品 served</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>[満足度評価ダイアログ]</span></span>
<span class="line"><span>   ⭐⭐⭐⭐⭐</span></span>
<span class="line"><span>   選択 + コメント (任意)</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        │ POST /api/customer/satisfaction-rating.php</span></span>
<span class="line"><span>        ▼</span></span>
<span class="line"><span>[評価保存 (satisfaction_ratings)]</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ 4-5 星 + Place ID あり ──→ [Google レビュー誘導]</span></span>
<span class="line"><span>        │                                    │</span></span>
<span class="line"><span>        │                                    ▼</span></span>
<span class="line"><span>        │                          https://search.google.com/local/writereview?placeid=...</span></span>
<span class="line"><span>        │                                    │</span></span>
<span class="line"><span>        │                                    ▼</span></span>
<span class="line"><span>        │                          [Google マップ レビュー投稿]</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        ├─ 1-2 星 ──→ [KDS 赤バナー警告]</span></span>
<span class="line"><span>        │                  │</span></span>
<span class="line"><span>        │                  ▼</span></span>
<span class="line"><span>        │             ホールスタッフが伺う</span></span>
<span class="line"><span>        │</span></span>
<span class="line"><span>        └─ 全評価 ──→ [スタッフ評価レポート / メニュー別レポート]</span></span></code></pre></div><h2 id="_20-10-実例" tabindex="-1">20.10 実例 <a class="header-anchor" href="#_20-10-実例" aria-label="Permalink to &quot;20.10 実例&quot;">​</a></h2><h3 id="_20-10-1-matsunoya-渋谷店-google-レビューで月-8-件獲得" tabindex="-1">20.10.1 matsunoya 渋谷店: Google レビューで月 8 件獲得 <a class="header-anchor" href="#_20-10-1-matsunoya-渋谷店-google-レビューで月-8-件獲得" aria-label="Permalink to &quot;20.10.1 matsunoya 渋谷店: Google レビューで月 8 件獲得&quot;">​</a></h3><p><strong>設定</strong>:</p><ul><li>Place ID: <code>ChIJrTLr-GyuEmsRBfy61i59si0</code> (松乃家 渋谷店)</li><li>満足度評価: ON</li><li>平均提供時間: 12 分</li></ul><p><strong>結果 (1 ヶ月)</strong>:</p><ul><li>満足度評価ダイアログ表示数: 480 件</li><li>評価実施率: 約 35% → 168 件評価</li><li>4-5 星評価: 142 件 (84%)</li><li>Google レビュー実投稿数: 8 件 (誘導から約 6%)</li><li>Google マップ平均星: 4.2 → 4.4 に上昇</li></ul><h3 id="_20-10-2-torimaru-個人店、place-id-未設定で運用" tabindex="-1">20.10.2 torimaru: 個人店、Place ID 未設定で運用 <a class="header-anchor" href="#_20-10-2-torimaru-個人店、place-id-未設定で運用" aria-label="Permalink to &quot;20.10.2 torimaru: 個人店、Place ID 未設定で運用&quot;">​</a></h3><p><strong>設定</strong>:</p><ul><li>Place ID: 未設定 (Google マップ未登録)</li><li>満足度評価: ON</li></ul><p><strong>結果</strong>:</p><ul><li>満足度評価のみ取得 → スタッフ評価レポートに活用</li><li>1-2 星評価が出たら店主が即座に対応</li><li>Google レビュー誘導は無効 (リンク表示されない)</li></ul><p><strong>学び</strong>: Google マップ未登録の店舗でも、満足度評価データだけで運用改善に使える。</p><h2 id="_20-11-競合調査機能との関係" tabindex="-1">20.11 競合調査機能との関係 <a class="header-anchor" href="#_20-11-競合調査機能との関係" aria-label="Permalink to &quot;20.11 競合調査機能との関係&quot;">​</a></h2><p><strong>Google Places API キー</strong> (<a href="./16-settings.html">POSLA 共通 API 設定</a>) は以下の機能で共通利用されます:</p><table tabindex="0"><thead><tr><th>機能</th><th>利用 API</th><th>章</th></tr></thead><tbody><tr><td><strong>Place ID 取得 (本章)</strong></td><td>Place ID Finder (手動)</td><td>20.4</td></tr><tr><td><strong>競合調査</strong></td><td>Places API Nearby Search</td><td><a href="./14-ai.html">14 章 14.4</a></td></tr><tr><td><strong>住所ジオコーディング</strong></td><td>Geocoding API</td><td>16 章</td></tr></tbody></table><p>API キー設定:</p><ul><li>POSLA 共通: <code>posla_settings.google_places_api_key</code></li><li>取得: <code>GET /api/posla/settings.php</code> (POSLA 管理者認証)</li><li>利用エンドポイント: <code>api/store/places-proxy.php</code> (CORS 回避 + キー非露出)</li></ul><div class="warning custom-block"><p class="custom-block-title">キー未設定時の挙動</p><p><code>google_places_api_key</code> が未設定だと:</p><ul><li>Place ID 設定欄は使える (手動取得・貼り付けのため)</li><li>ただし「競合調査」機能は <code>NO_API_KEY</code> (400) エラー</li><li>POSLA 運営にキー設定を依頼してください</li></ul></div><h2 id="_20-12-google-レビュー実装の技術詳細" tabindex="-1">20.12 Google レビュー実装の技術詳細 <a class="header-anchor" href="#_20-12-google-レビュー実装の技術詳細" aria-label="Permalink to &quot;20.12 Google レビュー実装の技術詳細&quot;">​</a></h2><h3 id="_20-12-1-高評価判定ロジック-menu-html-l2104" tabindex="-1">20.12.1 高評価判定ロジック (menu.html L2104) <a class="header-anchor" href="#_20-12-1-高評価判定ロジック-menu-html-l2104" aria-label="Permalink to &quot;20.12.1 高評価判定ロジック (menu.html L2104)&quot;">​</a></h3><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (rating </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 4</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> settings.googlePlaceId) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  var</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> reviewUrl </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://search.google.com/local/writereview?placeid=&#39;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">                  +</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> encodeURIComponent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(settings.googlePlaceId);</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // [⭐ Google でレビューを書く] ボタンを表示</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="_20-12-2-セキュリティ" tabindex="-1">20.12.2 セキュリティ <a class="header-anchor" href="#_20-12-2-セキュリティ" aria-label="Permalink to &quot;20.12.2 セキュリティ&quot;">​</a></h3><ul><li>API は <code>require_auth()</code> なし (お客様セルフオーダー)</li><li>代わりに <code>session_token</code> で改ざん防止</li><li><code>hash_equals($dbToken, (string)$inputToken)</code> でタイミング攻撃防御</li><li>同一注文への二重投稿は DB UNIQUE 制約で拒否</li></ul><h3 id="_20-12-3-評価データのプライバシー" tabindex="-1">20.12.3 評価データのプライバシー <a class="header-anchor" href="#_20-12-3-評価データのプライバシー" aria-label="Permalink to &quot;20.12.3 評価データのプライバシー&quot;">​</a></h3><ul><li>お客様の個人情報は <strong>保存しない</strong> (匿名のテーブルセッション単位)</li><li>コメント欄は最大 1000 文字、HTML エスケープ後 DB 保存</li><li>スタッフ評価レポートでは個別評価が見える (店長が確認可能)</li></ul><h2 id="_20-13-トラブルシューティング表-拡張版" tabindex="-1">20.13 トラブルシューティング表（拡張版） <a class="header-anchor" href="#_20-13-トラブルシューティング表-拡張版" aria-label="Permalink to &quot;20.13 トラブルシューティング表（拡張版）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>評価ダイアログが出ない</td><td>全品 served になっていない</td><td>KDS で全品を提供済にする</td></tr><tr><td>評価ダイアログが出ない</td><td>既に評価済み (DB UNIQUE)</td><td>同じ注文には 1 回のみ</td></tr><tr><td>評価ダイアログが出ない</td><td>satisfaction_rating_enabled = 0</td><td>店舗設定で ON に</td></tr><tr><td>Google レビューリンクが出ない</td><td>評価が 3 以下</td><td>仕様 (4-5 星のみ表示)</td></tr><tr><td>Google レビューリンクが出ない</td><td>Place ID 未設定</td><td>16 章 16.X で設定</td></tr><tr><td>Google レビューリンクが出ない</td><td>Place ID 形式不正</td><td><code>ChIJ</code> で始まる文字列を再取得</td></tr><tr><td>リンクが古い店舗を開く</td><td>Place ID 入力ミス</td><td>Place ID Finder で正しいものを再取得</td></tr><tr><td>リンクをタップしても投稿画面が開かない</td><td>お客様の Google 未ログイン</td><td>お客様が Google アカウントでログインする必要あり</td></tr><tr><td>評価データがレポートに反映されない</td><td>集計キャッシュ</td><td>翌日朝の日次集計後に反映</td></tr><tr><td>KDS の赤バナーが出ない</td><td>KDS 側の low-rating 設定</td><td>7.7.X 参照</td></tr><tr><td>多言語のお客様に英語で評価 UI が出ない</td><td>翻訳機能の問題</td><td>4 章 翻訳機能のトラブル参照</td></tr><tr><td>Place ID が変わってしまった</td><td>Google ビジネスプロフィールで店舗統合・移転</td><td>新 Place ID を取得して再設定</td></tr></tbody></table><h2 id="_20-14-kpi-ダッシュボードの作り方-推奨" tabindex="-1">20.14 KPI ダッシュボードの作り方（推奨） <a class="header-anchor" href="#_20-14-kpi-ダッシュボードの作り方-推奨" aria-label="Permalink to &quot;20.14 KPI ダッシュボードの作り方（推奨）&quot;">​</a></h2><h3 id="_20-14-1-月次で追うべき指標" tabindex="-1">20.14.1 月次で追うべき指標 <a class="header-anchor" href="#_20-14-1-月次で追うべき指標" aria-label="Permalink to &quot;20.14.1 月次で追うべき指標&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指標</th><th>目標値</th><th>取得方法</th></tr></thead><tbody><tr><td>満足度評価実施率</td><td>30% 以上</td><td><code>satisfaction_ratings.count / orders.count</code></td></tr><tr><td>平均星評価</td><td>4.5 以上</td><td><code>AVG(rating)</code></td></tr><tr><td>4-5 星比率</td><td>80% 以上</td><td><code>COUNT(rating&gt;=4) / COUNT(*)</code></td></tr><tr><td>Google レビュー実投稿数</td><td>月 5 件以上</td><td>Google ビジネスプロフィール ダッシュボード</td></tr><tr><td>Google マップ平均星</td><td>4.3 以上</td><td>同上</td></tr><tr><td>Google マップ閲覧数</td><td>前月比 +5%</td><td>同上</td></tr></tbody></table><h3 id="_20-14-2-改善施策" tabindex="-1">20.14.2 改善施策 <a class="header-anchor" href="#_20-14-2-改善施策" aria-label="Permalink to &quot;20.14.2 改善施策&quot;">​</a></h3><ul><li>評価実施率が低い → 評価ダイアログのデザイン改善 (POSLA 運営に要望)</li><li>平均星が低い → スタッフ研修、メニュー改善、提供時間短縮</li><li>Google レビュー数が伸びない → 高評価客にホールスタッフが「Google レビューもお願いします」と一声</li></ul><h2 id="_20-x-よくある質問-1" tabindex="-1">20.X よくある質問 <a class="header-anchor" href="#_20-x-よくある質問-1" aria-label="Permalink to &quot;20.X よくある質問&quot;">​</a></h2><p><strong>Q1.</strong> Place ID の取得方法</p><p><strong>A1.</strong> <a href="https://developers.google.com/maps/documentation/places/web-service/place-id" target="_blank" rel="noreferrer">Google Place ID Finder</a> で店舗名検索が最も簡単・確実。</p><p><strong>Q2.</strong> 低評価のお客様も Google に誘導される？</p><p><strong>A2.</strong> <strong>誘導されません</strong>（4〜5 星のみ）。1〜3 星は店舗に内部通知のみ。Google マップ上の評価が下がるリスクを減らします。</p><p><strong>Q3.</strong> 設定したのにレビューリンクが出ない</p><p><strong>A3.</strong> 以下を確認:</p><ul><li>セルフメニューを再読み込み（3 分のメニューキャッシュ）</li><li>Place ID が正しい形式（<code>ChIJ...</code> で始まる）</li><li>評価が 4 以上か（3 以下なら表示しない仕様）</li></ul><p><strong>Q4.</strong> Place ID 設定なしでも満足度評価は使える？</p><p><strong>A4.</strong> はい。満足度評価データは内部レポート用にも使えます。Google レビュー誘導だけが無効になる。</p><p><strong>Q5.</strong> 評価データはどこに保存される？</p><p><strong>A5.</strong> <code>satisfaction_ratings</code> テーブル。<code>orders.id</code> と紐付けて保存。</p><p><strong>Q6.</strong> 評価 UI のデザインを変えたい</p><p><strong>A6.</strong> 現状はカスタマイズ不可（POSLA 標準デザイン）。将来的にロゴ色・テーマカラーが反映される予定。</p><p><strong>Q7.</strong> お客様が複数回評価できる？</p><p><strong>A7.</strong> 同じ注文に対しては 1 回のみ。同じテーブルセッションで別の注文があれば、それぞれ評価可。</p><p><strong>Q8.</strong> 英語のお客様にも対応している？</p><p><strong>A8.</strong> はい。多言語対応（5 言語）で評価 UI が翻訳されます。Google レビュー画面は Google 側で多言語対応。</p><p><strong>Q9.</strong> Stripe Reader S700 とは関係ある？</p><p><strong>A9.</strong> ありません。S700 はカード決済用、満足度評価は注文後の完全に別フロー。</p><p><strong>Q10.</strong> Google レビュー数が増えない</p><p><strong>A10.</strong> 以下を確認:</p><ul><li>平均評価が 4 未満（リンク表示されない）</li><li>お客様がリンクをタップしていない（リンクが目立たない可能性）</li><li>Google アカウントを持っていない（投稿不可）</li><li>営業件数自体が少ない（来店数増加の施策も必要）</li></ul><p><strong>Q11.</strong> Google ビジネスプロフィールが必要？</p><p><strong>A11.</strong> はい。Place ID は Google ビジネスプロフィールに登録された店舗のみ取得可能です。</p><p><strong>Q12.</strong> Google レビューに返信できる？</p><p><strong>A12.</strong> POSLA からは不可。Google ビジネスプロフィール画面から店舗オーナーが返信してください。</p><p><strong>Q13.</strong> Place ID は変わる可能性がある？</p><p><strong>A13.</strong> 通常は変わりません。ただし店舗統合・移転・閉店などで変わる場合があります。年 1 回確認推奨。</p><p><strong>Q14.</strong> 満足度評価の集計はリアルタイム？</p><p><strong>A14.</strong> スタッフ評価レポートは日次集計、KDS 低評価アラートはリアルタイム (3 秒ポーリング)。</p><p><strong>Q15.</strong> 競合調査機能との API キー共有は安全？</p><p><strong>A15.</strong> はい。POSLA 共通 API キーは <code>posla_settings</code> 一括管理で、サーバーサイドプロキシ経由なので、クライアントには露出しません。</p><hr><h2 id="_20-y-トラブルシューティング-1" tabindex="-1">20.Y トラブルシューティング <a class="header-anchor" href="#_20-y-トラブルシューティング-1" aria-label="Permalink to &quot;20.Y トラブルシューティング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>原因</th><th>対処</th></tr></thead><tbody><tr><td>評価ダイアログが出ない</td><td>全品目が served になっていない</td><td>KDS で全品 served にする</td></tr><tr><td>評価ダイアログが出ない</td><td>既に評価済み</td><td>同じ注文には 1 回のみ</td></tr><tr><td>Google リンクが出ない</td><td>評価 3 以下 / Place ID 未設定</td><td>4-5 星かつ Place ID 設定要</td></tr><tr><td>Google リンクが古い店舗を開く</td><td>Place ID 入力ミス</td><td>Place ID 再取得・再設定</td></tr><tr><td>評価データがレポートに反映されない</td><td>キャッシュ</td><td>翌日まで待つ（一部レポートは日次集計）</td></tr></tbody></table><hr><h2 id="_20-z-技術補足-1" tabindex="-1">20.Z 技術補足 <a class="header-anchor" href="#_20-z-技術補足-1" aria-label="Permalink to &quot;20.Z 技術補足&quot;">​</a></h2><h3 id="db-1" tabindex="-1">DB <a class="header-anchor" href="#db-1" aria-label="Permalink to &quot;DB&quot;">​</a></h3><ul><li><code>satisfaction_ratings</code> テーブル <ul><li><code>id</code>, <code>tenant_id</code>, <code>store_id</code>, <code>table_id</code>, <code>order_id</code>, <code>order_item_id</code>（任意）, <code>menu_item_id</code>, <code>item_name</code>, <code>rating</code> (1-5), <code>comment</code>, <code>created_at</code></li></ul></li><li><code>store_settings.google_place_id</code> カラム</li><li><code>store_settings.satisfaction_rating_enabled</code> カラム（デフォルト 1）</li></ul><h3 id="api-1" tabindex="-1">API <a class="header-anchor" href="#api-1" aria-label="Permalink to &quot;API&quot;">​</a></h3><ul><li><code>POST /api/customer/satisfaction-rating.php</code> — 評価送信（認証なし、セッショントークン検証あり） <ul><li>パラメータ: <code>store_id</code>, <code>table_id</code>, <code>session_token</code>, <code>order_id</code>, <code>order_item_id</code>, <code>menu_item_id</code>, <code>item_name</code>, <code>rating</code></li><li>エラー: <code>MISSING_FIELDS</code> (400), <code>INVALID_RATING</code> (400, 1-5 範囲外), <code>INVALID_SESSION</code> (401)</li></ul></li></ul><h3 id="フロント-1" tabindex="-1">フロント <a class="header-anchor" href="#フロント-1" aria-label="Permalink to &quot;フロント&quot;">​</a></h3><ul><li><code>public/customer/menu.html</code> L2104 (高評価判定 + Google リンク表示)</li><li>評価 UI レンダリング: 同じ menu.html 内のインラインスクリプト</li></ul><h3 id="連携先-url-1" tabindex="-1">連携先 URL <a class="header-anchor" href="#連携先-url-1" aria-label="Permalink to &quot;連携先 URL&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://search.google.com/local/writereview?placeid={URLエンコードされた placeId}</span></span></code></pre></div><hr><h2 id="関連章-1" tabindex="-1">関連章 <a class="header-anchor" href="#関連章-1" aria-label="Permalink to &quot;関連章&quot;">​</a></h2><ul><li><a href="./13-reports.html">13. レポート</a> — スタッフ評価レポート集計</li><li><a href="./14-ai.html">14. AI アシスタント</a> — 競合調査機能 (Places API 共有)</li><li><a href="./16-settings.html">16. 店舗設定</a> — Google Place ID の設定手順</li><li><a href="./17-customer.html">17. セルフオーダー</a> — 17.W 満足度評価詳細</li><li><a href="./07-kds.html">7. KDS</a> — 7.7.X 低評価アラート</li></ul><h2 id="更新履歴" tabindex="-1">更新履歴 <a class="header-anchor" href="#更新履歴" aria-label="Permalink to &quot;更新履歴&quot;">​</a></h2><ul><li><strong>2026-04-19 (Batch-12)</strong>: 操作前チェックリスト / 入力フィールド詳細表 / 画面遷移 ASCII / matsunoya/torimaru 実例 / 競合調査連携 / KPI ダッシュボード / FAQ 拡張</li><li><strong>2026-04-19</strong>: 全面拡充（活用ストーリー、KPI、技術詳細、トラブル）</li><li><strong>2026-04-18</strong>: フル粒度化</li></ul>`,198)])])}const u=e(s,[["render",d]]);export{g as __pageData,u as default};
